#include <stdio.h>
#include <stdlib.h>

int cmp(const void *a, const void *b) {
    long long x = *(const long long *)a;
    long long y = *(const long long *)b;
    return (x > y) - (x < y);
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long *keys = (long long *)malloc(N * sizeof(long long));
        long long *arr = (long long *)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &arr[i]);
        long long X; scanf("%lld", &X);
        for (int i = 0; i < N; ++i) keys[i] = arr[i] & X;
        qsort(keys, N, sizeof(long long), cmp);
        long long ans = 0;
        long long cnt = 1;
        for (int i = 1; i < N; ++i) {
            if (keys[i] == keys[i-1]) cnt++;
            else { ans += cnt * cnt; cnt = 1; }
        }
        ans += cnt * cnt; // last group
        printf("%lld\n", ans);
        free(keys);
        free(arr);
    }
    return 0;
}

